+    fn config_set_creates_new_file_when_missing() {
+        let dir = tempdir().expect("tempdir");
+        let path = dir.path().join("fsfs.toml");
+        let cli = CliInput {
+            format: frankensearch_fsfs::OutputFormat::Json,
+            ..CliInput::default()
+        };
